class Solution {
    public String solveEquation(String equation) {
        String[] terms = equation.split("=");
        String left = terms[0];
        String right = terms[1];

        String x = "";
        int power = 0;

        StringBuilder result = new StringBuilder();

        while (true) {
            if (right.contains("x")) {
                String[] parts = right.split("x");
                x = parts[0];
                power = Integer.parseInt(parts[1]);
                right = parts[2];
            } else {
                String[] parts = right.split("\\D+");
                String num = parts[0];
                String sign = parts[1];
                String nextNum = parts[2];

                if (sign.equals("+")) {
                    result.append(nextNum);
                } else if (sign.equals("-")) {
                    result.append("-" + nextNum);
                } else {
                    result.append(nextNum);
                }

                result.append("x");
                result.append("=");
                result.append(num);
            }
        }
    }

    return result.toString();
}
